import { describe, expect, it } from "vitest";
import { encodeAssetCreateParams } from "@/lib/b20/encode";

/** Params from successful CLI createB20 on Base Sepolia (tx 0x8b08b667…). */
const CLI_BASE_OS_PARAMS =
  "" as const;

describe("encodeAssetCreateParams", () => {
  it("matches base-std / forge abi.encode(B20AssetCreateParams)", () => {
    const encoded = encodeAssetCreateParams(
      "Base OS",
      "BOS",
      "0x8655520b4b19187038aC9a4f560da0979Cc1E95C",
      18
    );
    expect(encoded).toBe(CLI_BASE_OS_PARAMS);
  });
});
